        balloon: 2048,
        shares: 2000,
    },
    network: {
        net0: {
            bridge: "vmbr0",
            model: "virtio",
            tag: 100,
            firewall: true,
            rateLimit: 100,
        },
    },
    disk: {
        scsi0: {
            datastoreId: "local-lvm",
            sizeGb: 100,
            discard: "on",
            iothread: true,
            ssd: true,
            cache: "writethrough",
        },
    },
    vga: {
